var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"며칠 뒤","JPN":"数日後","ENG":"A few days later","TWN":"幾天後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 꼬맹이 뭔가 이상하지 않냐?","JPN":"おい、おこちゃま。おかしくないか？","ENG":"Hey, kid. Doesn't this feel weird to you?","TWN":"喂，小鬼不覺得有點奇怪嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"뭐가요?","JPN":"何が？","ENG":"What does?","TWN":"什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"우리가 이 병원 퇴원한 게, 채 한 달도 안 지났다고.","JPN":"私たちがこの病院を退院してから、まだ一か月も経ってないんだけど。","ENG":"It hasn't even been a month since we were discharged from this hospital.","TWN":"我們從這家醫院出院還不到一個月呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"근데 왜 우린 또 여기 입원해 있는 거냐?","JPN":"なのになんで、私たちはまたここに入院してるんだ？","ENG":"So why are we back here again?","TWN":"不過我們為什麼會住院在這裡啊？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"글쎄요? 미라처럼 붕대 둘둘 감은 채로 그런 말 해봤자 소용없지 않을까요?","JPN":"さあ？　ミイラみたいに包帯でぐるぐる巻きにされてそんなこと言っても何も変わらないと思うけど？","ENG":"Well, wrapped up like a mummy in bandages, you're hardly one to complain, don't you think?","TWN":"嗯，被繃帶包得像木乃伊的你，還真沒資格抱怨呢，你不覺得嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"의사 선생님 말씀 못 들었어요? 살아있는 게 기적이라면서요.","JPN":"お医者さんが言ってたでしょ？　生きてるのが奇跡だって。","ENG":"Didn't you hear what the doctor said? Just being alive is a miracle.","TWN":"你沒聽醫生說嗎？活著就是奇蹟。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아무렴, 6종 침식체한테 얻어맞았는데 살아 돌아온 게 기적이긴 하지.","JPN":"まあ、第6種侵食体にぶん殴られて、生きて帰れたんだからそりゃ奇跡だろ。","ENG":"Yeah, no kidding. Getting pounded by a Category 6 C.O. and making it out? That's a miracle in itself.","TWN":"當然，被6類侵蝕體打了還能活著回來確實是個奇蹟。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그 무저갱에서 보냈던 시간이 현실에서는 고작 3시간 남짓이었다는 게 말이 되냐?","JPN":"あの奈落の底にいた時間が、現実ではたったの3時間程度だったなんて、そんなの信じられる？","ENG":"But how do you explain the fact that we spent hours down in that abyss, and only three hours passed in the real world?","TWN":"在那個無底洞中度過的時間在現實中竟然只有短短3小時，這說得通嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하아, 진짜 우리 어떻게 살아서 돌아온 거냐?","JPN":"はあ、なんで私たち生きて帰って来れたんだ？","ENG":"*Sigh* How did we even make it back alive?","TWN":"哈，真是的，我們到底是怎麼活著回來的？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"난 아직도 현실감이 안 온다, 야.","JPN":"いまだに現実味がないわ。","ENG":"Still doesn't feel real.","TWN":"我現在都還不太敢相信，哎。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"고마워요, 라이카.","JPN":"ありがとう、ライカ。","ENG":"Thanks, Laika.","TWN":"謝謝你，萊卡。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐야, 뜬금없이? 너도 고백하게?","JPN":"何だ、急に？　あんたも告白でもする気？","ENG":"Huh? Where's that coming from? You about to confess or something?","TWN":"怎麼了，突然這樣？你也要告白嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그, 그런 거 아니라고요!","JPN":"そ、そんなんじゃないわよ！","ENG":"What?! Of course not!","TWN":"不、不是那樣的！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이번에 라이카가 저를 지켜주느라, 많이 다쳐 버렸으니까…….","JPN":"今回はライカが私を守るために、いっぱい怪我しちゃったから……","ENG":"You got pretty banged up protecting me this time, so...","TWN":"這次為了保護我，萊卡受了重傷……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아서라, 우리는 서로 뒤 봐주는 파트너잖아? 때때로 포지션을 바꿔 줄 필요도 있는 거지.","JPN":"よせって。私たちは互いに尻拭いするパートナーだろ？　たまにはポジションを変えてみるのも悪くないってもんだ。","ENG":"Come on, we've always got each other's backs. Just means it was my turn to take the hit.","TWN":"亞瑟拉，我們是互相照應的夥伴吧？有時候也需要換換位置呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"으아, 저질이에요. 라이카. 완전 아저씨 같아.","JPN":"うわっ、最低。ライカ、今完全におっさんだったよ。","ENG":"Ugh, that's so gross. You sound like some sleazy old guy.","TWN":"哎呀，真是太糟糕了。萊卡完全像個大叔。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그리고 고백 같은 건 신중히 생각해. 괜히 잘못 박으면 오히려 어색한 사이 된다고?","JPN":"それに告白とかは慎重に考えな。下手したらかえって気まずくなりかねないから。","ENG":"Well, just think carefully before you confess to someone. One wrong move and it gets super awkward.","TWN":"還有，告白這種事情要慎重考慮。萬一搞錯了，反而會變得尷尬喔？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"쟤들처럼 말이야.","JPN":"あいつらみたいに。","ENG":"Just like those two.","TWN":"就像他們一樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"흠흠! 이거 다시 봤다고, 얼빵이.","JPN":"おっほん！　見直したよ、間抜け。","ENG":"Ahem! I saw a different side of you, goon.","TWN":"哼哼！？對你有改觀了，小呆瓜。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"마냥 얼빵하기만 한 줄 알았는데, 의외로 대범한 구석이 있잖아?","JPN":"ただ間抜けなだけかと思ったら、意外と大胆なところもあるんだな？","ENG":"Thought you were all clueless, but turns out you've got guts after all.","TWN":"原以為只是個傻乎乎的傢伙，沒想到還有大膽的一面呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래, 괜찮아. 이 언니는 네 취향을 존중한단다.","JPN":"いいっていいって。好みって人それぞれだし。","ENG":"It's fine. I support your taste.","TWN":"好吧，沒關係。姊姊尊重你的喜好。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그, 그, 그, 그, 그건 그러니까……!","JPN":"そ、そ、そ、そ、その、だから……！","ENG":"Th-th-th-that's not what I–!","TWN":"那、那、那、那個！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"평소에 생각만 하고 있던 게 갑자기 말로 튀어나와 버려서…….","JPN":"普段思ってたことが、急に口から出てきちゃって……","ENG":"It just kind of slipped out! I didn't mean to say it out loud...!","TWN":"平時只是想想的事情突然脫口而出……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그게 고백이지, 별 게 고백이냐?","JPN":"それが告白ってもんだろ？","ENG":"That's called a confession, sweetheart. Plain and simple.","TWN":"那就是告白，告白有什麼？不了的？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아무튼 축하한다고, 얼빵아. 예쁜 사랑해.","JPN":"とにかくおめでとう、間抜け。いい恋しろよ。","ENG":"Anyway, congrats, goon. Hope it turns out sweet.","TWN":"總之，祝賀你，傻瓜。祝你愛情美滿。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"하으으…….","JPN":"はうぅ……","ENG":"Uggghh...","TWN":"哈啊……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"라이카! 적당히 좀 하지?","JPN":"ライカ！　いい加減にしたらどう？","ENG":"Laika! Would you knock it off?","TWN":"萊卡！？可而止吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"화낸다?","JPN":"怒るよ？","ENG":"I'm seriously gonna lose it.","TWN":"生氣嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"앗차차…! 아프다! 아파! 배가 아파……!","JPN":"おっとと……！　いたっ！　痛い！　腹が痛い……！","ENG":"Ack...! It hurts! My stomach...!","TWN":"啊哎喲！？疼！！子疼！？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"허신한테 맞아서 뚫려버린 배가 갑자기 너무 아파……!","JPN":"虚神に殴られて穴の開いた腹が、急にめちゃくちゃ痛いな……！","ENG":"My stomach that got blasted through by a Hollow God is hurting so much...!","TWN":"被虛神打穿的肚子突然好痛！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"허걱! 괜찮아요, 라이카!?","JPN":"ええっ！？　ライカ、大丈夫！？","ENG":"Oh no! Are you okay, Laika?!","TWN":"哎呀！？沒事吧，萊卡！？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이게 진짜……!","JPN":"このっ……！","ENG":"Unbelievable...!","TWN":"你！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"라이카! 노엘 좀 그만 놀리라고…! 죽는다! 진짜……!","JPN":"ライカ！　ノエルをからかうのもいい加減にして……！　じゃないと……！","ENG":"Laika! Stop teasing Noelle already! I'll kill you myself if you keep it up...!","TWN":"萊卡！？再捉弄洛艾兒了！？死的！？的！？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"으악…! 유미나! 나 중상이야, 중상! 이 중에서 제일 중상이라고……!","JPN":"うぐっ……！　ミナ！　私重症だって！　この中で一番重症……！","ENG":"Aaaaagh...! Yoo Mina! I'm the one with the worst injuries here! The worst...!","TWN":"嗚啊…… 劉米娜！？我重傷了，重傷！？裡面我最重傷！？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"살려줘, 펠리세트…! 이러다 나 죽어……!","JPN":"助けて、フェリセット！　私死んじゃう……！","ENG":"Félicette, help...! I'm gonna die at this rate...!","TWN":"救救我，費莉塞特！？樣下去我會死的！？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"에휴, 그냥 죽어요. 라이카.","JPN":"はあ、もう死んでいいよ、ライカ。","ENG":"*Sigh* Just die already, Laika.","TWN":"哎，乾脆去死吧，萊卡。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"으음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"무슨 소란이지?","JPN":"何の騒ぎだ。","ENG":"What's with all the noise?","TWN":"發生什麼？動了？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"소대장? 여긴 어쩐 일이야?","JPN":"小隊長？　どうしたの？","ENG":"Commander? What are you doing here?","TWN":"隊長？怎麼會在這裡？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어쩐 일이냐고? 이거 섭섭하군. 소대장이 돼서 소대원 병문안도 못 오나?","JPN":"どうしたとは、悲しいな。小隊長が隊員の見舞いに来てはいけないのか？","ENG":"What am I doing here? Well, that's rude. Can't a Division Commander check in on her squad members?","TWN":"問我有什麼？嗎？這讓我很傷心啊。難道當了小隊長就不能來看望小隊員了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"받아. 오다 주웠다.","JPN":"受け取れ、その辺で拾ったものだ。","ENG":"Here. Brought you something on the way.","TWN":"接著，路上撿來的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐야, 과일 사 온 거야?","JPN":"え？　果物買ってきたんだ。","ENG":"What's this, fruit?","TWN":"什麼？，買水果回來了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"오늘 왜 그래? 평소에는 이런 거 신경도 안 쓰더니?","JPN":"今日はどうしちゃったの？　いつもはこんなこと、気づかう人じゃないのに。","ENG":"What's gotten into you today? You normally don't care about this kind of thing.","TWN":"今天怎麼了？平時都不在意這些的？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"대강의 사정은 관리자 녀석에게 들었다.","JPN":"大体の事情は管理者のやつから聞いている。","ENG":"I got the general rundown from the Administrator.","TWN":"我聽管理者那傢伙說了個大概。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그런 무모한 작전을 신입, 너 혼자에게 떠맡기다니… 하여간 그 녀석도 제정신이 아니군.","JPN":"あんな無謀な作戦を新人、お前一人に任せるとは……まったく、やつの正気を疑うな。","ENG":"To think he dumped that reckless mission on a rookie like you... He's seriously lost it.","TWN":"居然把這麼魯莽的作戰任務交給新人你一個人……真是的，那傢伙也不正常啊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 나 혼자였다면 노엘을 구할 수 없었어.","JPN":"ううん、私一人だったらノエルを助けられなかった。","ENG":"No, I couldn't have saved Noelle on my own.","TWN":"不，如果只有我一個人，是無法救洛艾兒的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여기 있는 펠리세트, 라이카 그리고 에이미. 그 밖에 우리를 도와준 사람들이 있어.","JPN":"ここにいるフェリセットにライカ、そしてエイミー。その他にも私たちの背中を押してくれた人々がいる。","ENG":"It was Félicette, Laika, Amy, and others who helped.","TWN":"這裡有費莉塞特、萊卡和艾米。還有其他幫助過我們的人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 모두가 함께 있어서, 비로소 노엘을 구해낼 수 있었던 거야.","JPN":"そのみんなのおかげで、やっとノエルを助け出せたんだ。","ENG":"Without everyone, I never could've brought her back.","TWN":"正因為大家齊心協力，才能成功救出洛艾兒。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"노엘…….","JPN":"ノエル……","ENG":"Noelle...","TWN":"洛艾兒……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그렇군, 네가 펜릴 소대에 새로 들어온 신입인가?","JPN":"そうか、お前がフェンリル小隊に新しく入った新入りか。","ENG":"I see. You're the new rookie in Fenrir Squad, huh?","TWN":"原來如此，你是剛加入芬里爾小隊的新人嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우오오오오오오오……!","JPN":"むおおおおおおお……！","ENG":"Ooooooh...!","TWN":"嗚噢噢噢噢噢噢噢！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"설마설마 말로만 듣던 그 힐데 소대장님이신가요……?","JPN":"まさかまさか、あなたがあのヒルデ小隊長ですか……？","ENG":"Is that really you? The legendary Commander Hilde?!","TWN":"難道難道是傳說中的希爾德隊長嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L41_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우와아~ 대단해! 저 실제로는 처음 봐요!","JPN":"うわあ～　すごいです！　実物、初めて見ました！","ENG":"Woooow! This is amazing! I've never met you in person before!","TWN":"哇啊~太厲害了！？還是第一次見到呢！？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐지, 이 반응은? 이상한 녀석이군.","JPN":"何だ、この反応は。おかしなやつだな。","ENG":"What's with her reaction? What a strange girl.","TWN":"什麼？，這反應？真是個奇怪的傢伙。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아하하… 노엘이 좀 독특해서…….","JPN":"あはは……その子、ちょっと変わってて……","ENG":"Ahaha... Noelle's just... a bit unique.","TWN":"啊哈哈……洛艾兒有點特別……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"펜릴의 신입 소대원! 노엘 라이트. 소대장님께 인사 올리겠습니다……!","JPN":"フェンリルの新参隊員！　ノエル・ライト。小隊長にご挨拶申し上げます……！","ENG":"Rookie of Fenrir Squad! Noelle Wright, reporting in, ma'am...!","TWN":"芬里爾的新隊員！？艾兒·萊特。向小隊長問好！？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아하하! 역시 소문이랑 사실은 다른 가봐요!","JPN":"あはは！　やっぱり噂と本当って違うんですね！","ENG":"Ahaha! Guess rumors don't always match reality!","TWN":"啊哈哈！？然傳聞和事實不一樣啊！？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"소문? 무슨 소문을 말하는 거지?","JPN":"噂？　何の噂だ？","ENG":"Rumors? What rumors?","TWN":"傳聞？什麼？聞？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저는 여태껏 소대장님을 코핀의 <color=#ffd34c>도살마녀</color>라고 알고 있었거든요!","JPN":"私、今まで小隊長のこと、コフィンの<color=#ffd34c>屠殺魔女</color>としか知らなかったんです！","ENG":"Well, I always heard you were the Coffin's <color=#ffd34c>Butcher Witch</color>!","TWN":"我一直以為小隊長是科芬的<color=#ffd34c>屠殺魔女</color>呢！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그래서 엄청 긴장했는데……!","JPN":"だからすごく緊張してたんですけど……！","ENG":"So I was super nervous...!","TWN":"所以我非常緊張！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"충격! 이렇게 쬐그맣고 귀여울 줄이야! 소대장님을 인형 굿즈로 내면 대박이 날 거예요!","JPN":"びっくりです！　こんなに小さくて可愛いなんて！　小隊長のぬいぐるみグッズとか出したら、大人気間違いなしですって！","ENG":"No way! You're this small and cute?! A plush toy of you would be a huge hit!","TWN":"震驚！？想到會這麼小巧可愛！？果把小隊長做成玩偶周邊的話一定會大賣的！？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"何だと？","ENG":"Excuse me?","TWN":"什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"호, 혹시…! 실례가 안 된다면, 소대장님을 한 번 안아봐도 될까요……?","JPN":"あ、あの……！　もし失礼じゃなければ、小隊長をギュッてしてみてもいいですか……？","ENG":"U-um...! If it's not too much to ask, could I hug you...?","TWN":"喔，那個！？果不介意的話，我可以抱一下小隊長嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"한 품에 폭 안길 것 같은……","JPN":"腕の中にすっぽり入りそうな……","ENG":"You just look so huggable...","TWN":"好像會被緊緊擁入懷中……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"꾸에엑!?","JPN":"ぐええっ！？","ENG":"GAAAH?!","TWN":"呃啊！？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"실례가 돼.","JPN":"失礼だ。","ENG":"It is too much to ask.","TWN":"失禮了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"에휴, 앞 길이 막막하네, 저 녀석.","JPN":"はあ、前途多難だね、あいつ。","ENG":"Ugh, she's got a long road ahead of her.","TWN":"唉，前路渺茫啊，那傢伙。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어쨌든 이번 일은 고생했다, 신입.","JPN":"とにかく。今回の件はご苦労だった、新人。","ENG":"Anyway, good work, rookie.","TWN":"不管怎樣，這次辛苦了，新人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"정보 말소의 해결, 초고심도 다이브, 고철 더미의 시험, 스완의 계획 저지…….","JPN":"情報抹消の解決、超高深度のダイブ、鉄くずの試験、スワンの計画の阻止……","ENG":"Fixing information erasure, diving into the hyperdepths, passing the Scraps' test, stopping Swan's plan...","TWN":"資訊抹消的解決，超高深度躍入，廢鐵的試驗，阻止史旺的計畫……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"무엇 하나 쉬운 일이 없었을 텐데 말이지.","JPN":"何一つ簡単なことではなかったはず。","ENG":"None of that could've been easy.","TWN":"沒有一件事情是容易的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"소대장…….","JPN":"小隊長……","ENG":"Commander...","TWN":"小隊長……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"내친김에 신입, 신입의 신입을 부탁하지.","JPN":"ついでだ、新人。新入りの新人をお前に任せる。","ENG":"Since we're here, rookie, I'll leave the new rookie to you.","TWN":"既然這樣，新人，拜託你照顧新人中的新人吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"신입의 신입?","JPN":"新入りの新人？","ENG":"The new rookie?","TWN":"新人中的新人？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래, 아무래도 신입의 신입은 나보다 신입……. 역시 호칭이 거슬리는군.","JPN":"そうだ、どうも新入りの新人は、私よりも新人……ややこしいな。","ENG":"Yeah, the new rookie's even greener than I am... Ugh, that title's really starting to bug me.","TWN":"是啊，畢竟新人中的新人比我還要新……果然這個稱呼讓人不舒服。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 아무튼 이제 후배도 생겼으니, 신입 딱지는 뗄 때도 됐겠지.","JPN":"まあ、もう後輩もできたことだし、新人卒業でもいいだろう。","ENG":"Anyway, you've got someone under you now, so it's about time to ditch the rookie label, don't you think?","TWN":"嗯，總之現在有了後輩，也該摘掉新人標籤了吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그렇지 않나, 유미나?","JPN":"そうだろう？　ヤナギ・ミナ。","ENG":"Wouldn't you agree, Yoo Mina?","TWN":"不是嗎？劉米娜？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"훗, 뭐야 그게.","JPN":"ふっ、なにそれ。","ENG":"Pfft. What?","TWN":"哼，為什麼？這麼想呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좋아, 맡겨 달라고. 소대장.","JPN":"いいよ、任せて。小隊長。","ENG":"All right, leave it to me, Commander.","TWN":"好，交給我吧，隊長。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭐죠? 이 펜릴답지 않은 훈훈한 분위기는……?","JPN":"何ですか？　フェンリルらしからぬ、この穏やかな雰囲気は……？","ENG":"What's this? Since when was Fenrir Squad this heartwarming...?","TWN":"這是什麼？這種不符合芬里爾的溫馨氛圍是?"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부사장님?","JPN":"副社長？","ENG":"Vice President?","TWN":"副總？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이수연, 네가 여기 왔다면 뻔하겠군.","JPN":"カナミ、お前がここに来たということは……","ENG":"Lee Sooyeon, I can guess why you're here.","TWN":"李秀妍，果然是你來了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"관리자 녀석이 이 녀석들을 호출하는 건가?","JPN":"管理者がこいつらを呼んでるのか？","ENG":"The Administrator's calling them, isn't he?","TWN":"是管理者那傢伙在召喚他們嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하여간 눈치도 빠르시군요.","JPN":"相変わらず目敏いですね。","ENG":"As sharp as ever, I see.","TWN":"你可真有眼力見。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양 그리고 노엘 양. 사장님께서 부르십니다.","JPN":"ミナさん、そしてノエルさん。社長がお呼びです。","ENG":"Yoo Mina, Noelle. Boss would like a word.","TWN":"米娜，還有洛艾兒。老闆在叫你們。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아무래도 이번 사건과 관련하여 중요한 말씀이 있는 모양이더군요.","JPN":"今回の事件に関して、大事なお話があるとのことです。","ENG":"It seems he has something important to discuss regarding this incident.","TWN":"看來關於這次事件有重要的事情要說呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"중요한 말씀이라고요……?","JPN":"大事な話ですか……？","ENG":"Something important...?","TWN":"重要的話?"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};